    - <style>
        :root {
            --ubuntu-orange: #E95420;
            --ubuntu-purple: #300a24;
            --ubuntu-dark: #2c001e;
            --window-bg: #f2f2f2;
            --taskbar-bg: rgba(0, 0, 0, 0.6);
            --text-color: #333;
        }

        * { box-sizing: border-box; margin: 0; padding: 0; user-select: none; }

        body, html {
            width: 100%;
            height: 100%;
            overflow: hidden;
            font-family: 'Ubuntu', sans-scale, Arial, sans-serif;
        }

        #desktop {
            width: 100vw;
            height: 100vh;
            background: linear-gradient(135deg, var(--ubuntu-purple) 0%, var(--ubuntu-dark) 100%);
            position: relative;
            overflow: hidden;
        }

        /* Taskbar/Dock */
        #taskbar {
            position: absolute;
            bottom: 10px;
            left: 50%;
            transform: translateX(-50%);
            background: var(--taskbar-bg);
            backdrop-filter: blur(10px);
            padding: 8px 20px;
            border-radius: 30px;
            display: flex;
            gap: 15px;
            align-items: center;
            z-index: 1000;
            border: 1px solid rgba(255, 255, 255, 0.1);
        }

        #taskbar button {
            background: transparent;
            border: none;
            color: white;
            padding: 8px 15px;
            cursor: pointer;
            font-size: 14px;
            border-radius: 5px;
            transition: background 0.2s;
        }

        #taskbar button:hover {
            background: rgba(255, 2    55, 255, 0.2);
        }

        /* Window Styles */
        .window {
            position: absolute;
            top: 50px;
            left: 50px;
            width: 600px;
            height: 400px;
            background: var(--window-bg);
            border-radius: 8px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.5);
            display: none;
            flex-direction: column;
            overflow: hidden;
            resize: both;
        }

        .window-header {
            background: #e0e0e0;
            padding: 10px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            cursor: grab;
            border-bottom: 1px solid #ccc;
        }

        .window-header:active { cursor: grabbing; }

        .window-title {
            font-size: 14px;
            font-weight: bold;
            color: var(--text-color);
            padding-left: 5px;
        }

        .win-close {
            background: #ff5f56;
            border: none;
            width: 12px;
            height: 12px;
            border-radius: 50%;
            cursor: pointer;
        }

        .window-content {
            flex: 1;
            overflow: auto;
            position: relative;
            color: var(--text-color);
        }

        /* Files App Styles */
        #files-path {
            padding: 8px;
            background: #eee;
            font-size: 13px;
            border-bottom: 1px solid #ddd;
