        .fs-item:hover { background: rgba(0,0,0,0.05); }

        .fs-icon {
            width: 40px;
            height: 40px;
            margin-bottom: 5px;
            background: #ccc;
            border-radius: 4px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 20px;
