</head>
<body>

<div id="desktop">
    <!-- Files Window -->
    <div id="files-window" class="window">
        <div class="window-header">
            <span class="window-title">Files</span>
            <button class="win-close"></button>
        </div>
        <div id="files-path">
            <button id="files-up">Up</button>
            <span id="current-path-text">/</span>
        </div>
        <div class="window-content">
            <div class="fs-list" id="fs-container">
                <!-- Items injected by JS -->
            </div>
        </div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window">
        <div class="window-header">
            <span class="window-title">Notepad</span>
            <button class="win-close"></cut></button>
        </div>
        <div id="tabs">
            <!-- Tabs injected by JS -->
            <button id="new-tab">+</button>
        </div>
        <div class="window-content" style="padding:0;">
            <textarea id="editor"></textarea>
        </div>
    </div>

    <!-- Taskbar -->
    <div id="taskbar">
        <button id="open-files">Files</button>
        <button id="open-notepad">Notepad</button>
    </div>
</div>

<script>
    /** 
     * FILESYSTEM LOGIC
     */
    const fsTree = {
        name: '/',
        type: 'dir',
        parent: null,
        children: [
            { name: 'bin', type: 'dir', parent: null, children: [] },
            { name: 'etc', type: 'dir', parent: null, children: [] },
            { name: 'home', type: 'dir', parent: null, children: [
                { name: 'user', type: 'dir', parent: null, children: [
                    { name: 'Documents', type: 'dir', parent: null, children: [] },
                    { name: 'Downloads', type: 'dir', parent: null, children: [] },
                    { name: 'Pictures', type: 'dir', parent: null, children: [] }
                ]}
            ]},
            { name: 'usr', type: 'dir', parent: null, children: [] },
            { name: 'var', type: 'dir', parent: null, children: [] }
        ]
    };

    // Link parents for traversal
    function linkParents(node, parent) {
        node.parent = parent;
        if (node.children) {
            node.children.forEach(child => linkParents(child, node));
        }
    }
    linkParents(fsTree, null);

    let currentDir = fsTree;

    const fsContainer = document.getElementById('fs-container');
    const pathText = document.getElementById('current-path-text');
    const filesUpBtn = document.getElementById('files-up');

    function getFullPath(node) {
        let parts = [];
        let curr = node;
        while (curr && curr.name !== '/') {
            parts.unshift(curr.name);
            curr = curr.parent;
        }
        return '/' + parts.join('/');
    }

    function renderFiles() {
        fsContainer.innerHTML = '';
        pathText.innerText = getFullPath(currentDir);

        currentDir.children.forEach(item => {
            const div = document.createElement('div');
            div.className = 'fs-item';

            const icon = document.createElement('div');
            icon.className = 'fs-icon';
            icon.innerText = item.type === 'dir' ? '📁' : '📄';

            const label = document.createElement('span');
            label.innerText = item.name;

            div.appendChild(icon);
            div.appendChild(label);

            div.addEventListener('dblclick', () => {
                if (item.type === 'dir') {
                    currentDir = item;
                    renderFiles();
                }
            });

            fsContainer.appendChild(div);
        });
    }

    filesUpBtn.addEventListener('click', () => {
        if (currentDir.parent) {
            currentDir = currentDir.parent;
            renderFiles();
        }
    });

    /** 
     * NOTEPAD LOGIC
     */
    let tabs = [];
    let activeTabId = null;

    const tabsContainer = document.getElementById('tabs');
    const newTabBtn = document.getElementById('new-tab');
    const editor = document.getElementById('editor');

    function loadNotepad() {
        const saved = localStorage.getItem('ubuntu_notepad');
        if (saved) {
            const data = JSON.parse(saved);
            tabs = data.tabs;
            activeTabId = data.activeTabId;
        } else {
            const initialId = Date.now();
            tabs = [{ id: initialId, title: 'Untitled', content: '' }];
            activeTabId = initialId;
        }
        renderTabs();
        switchTab(activeTabId);
    }

    function saveNotepad() {
        localStorage.setItem('ubuntu_notepad', JSON.stringify({ tabs, activeTabId }));
    }

    function renderTabs() {
        // Clear existing tabs (keep the + button)
        const buttons = tabsContainer.querySelectorAll('.tab');
        buttons.forEach(b => b.remove());

        tabs.forEach(tab => {
            const tabEl = document.createElement('div');
            tabEl.className = 'tab' + (tab.id === activeTabId ? ' active' : '');
            tabEl.innerText = tab.title;
            tabEl.addEventListener('click', () => switchTab(tab.id));
            tabsContainer.insertBefore(tabEl, newTabBtn);
        });
    }

    function switchTab(id) {
        activeTabId = id;
        const tab = tabs.find(t => t.id === id);
        editor.value = tab ? tab.content : '';
        renderTabs();
        saveNotepad();
    }

    newTabBtn.addEventListener('click', () => {
        const newId = Date.now();
        tabs.push({ id: newId, title: 'New Tab', content: '' });
        activeTabId = newId;
        renderTabs();
        switchTab(newId);
    });

    editor.addEventListener('input', (e) => {
        const tab = tabs.find(t => t.id === activeTabId);
        if (tab) {
            tab.content = e.target.value;
            saveNotepad();
        }
    });

    /** 
     * SHELL / WINDOW MANAGEMENT
     */
    const filesWin = document.getElementById('files-window');
    const notepadWin = document.getElementById('notepad-window');
    const openFilesBtn = document.getElementById('open-files');
    const openNotepadBtn = document.getElementById('open-notepad');

    openFilesBtn.addEventListener('click', () => {
        filesWin.style.display = 'flex';
    });

    openNotepadBtn.addEventListener('click', () => {
        notepadWin.style.display = 'flex';
    });

    document.querySelectorAll('.win-close').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.target.closest('.window').style.display = 'none';
        });
    });

    // Simple Draggable Logic
    document.querySelectorAll('.window-header').forEach(header => {
        let isDragging = false;
        let offset = { x: 0, y: 0 };

        header.addEventListener('mousedown', (e) => {
            isDragging = true;
            const win = header.parentElement;
            offset.x = e.clientX - win.offsetLeft;
            offset.undercut = e.clientY - win.offsetTop; // Using a different name to avoid conflict
            offset.y = e.clientY - win.offsetTop;
        });

        window.addEventListener('mousemove', (e) => {
            if (!isDragging) return;
            const win = header.parentElement;
            win.style.left = (e.clientX - offset.x) + 'px';
            win.style.top = (e.clientY - offset.y) + 'px';
        });

        window.addEventListener('mouseup', () => {
            isDragging = false;
        });
    });

    // Init
    renderFiles();
    loadNotepad();

</script>
</body>
</html>
